// @ts-nocheck
import { useTerminalStore } from '../store/terminal';
import { notify } from './notify';

/** Load SQL into the bottom Terminal panel (expands and selects connection). */
export function sendSqlToTerminal(payload: {
  connectionId: string;
  sql: string;
  database?: string | null;
  autoRun?: boolean;
  notifyMessage?: string | false;
}) {
  const sql = String(payload.sql ?? '').trim();
  if (!sql || !payload.connectionId) return false;

  useTerminalStore.getState().openTerminal({
    connectionId: payload.connectionId,
    database: payload.database ?? null,
    sql,
    autoRun: !!payload.autoRun,
  });
  if (payload.notifyMessage !== false) {
    notify(payload.notifyMessage ?? 'SQL enviado al Terminal — panel expandido');
  }
  return true;
}
